/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[DataEventHandler(tableStr(PurchPackingSlipTmp), DataEventType::Inserting)]
public static void PurchPackingSlipTmp_onInserting(Common sender, DataEventArgs e)
{
    PurchPackingSlipTmp purchPackingSlipTmp = sender as PurchPackingSlipTmp;

    PurchLine purchLine;
    VendPackingSlipJour vendPackingSlipJour;
    InventDim inventDim;

    select firstOnly vendPackingSlipJour
where vendPackingSlipJour.RecId == purchPackingSlipTmp.JournalRecId;

    if (vendPackingSlipJour)
    {
        select firstOnly purchLine
    where (purchLine.PurchId == vendPackingSlipJour.PurchId &&
           purchLine.ItemId == purchPackingSlipTmp.ItemId);

        if (purchLine)
        {
            select firstOnly inventDim
        where inventDim.InventDimId == purchLine.InventDimId;

            if (inventDim)
            {
                purchPackingSlipTmp.ETGInventBatchId = inventDim.InventBatchId;
            }
        }
    }

}
